from pydantic import BaseModel, field_validator
from pydantic_ai import Agent
from semantic_similarity import cosine_sim

class FlexibleResponse(BaseModel):
    @field_validator('content')
    @classmethod
    def fuzzy_validate(cls, v, info):
        expected_schema = info.context.get('expected_schema')
        if cosine_sim(v, expected_schema) > 0.8:
            return v  # Accept semantically similar
        raise ValueError('Semantic mismatch')

agent = Agent(response_model=FlexibleResponse)

from pydantic_ai import Agent
from functools import wraps

def observable_retry(max_retries=3):
    def decorator(func):
        @wraps(func)
        async def wrapper(*args, **kwargs):
            for attempt in range(max_retries):
                try:
                    return await func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_retries - 1:
                        raise
                    print(f'Retry {attempt + 1}: {e}')
        return wrapper
    return decorator

